const out = [];
const updateItems = $('Update Unpaid Orders').all();
const pendingItems = $('Get Pending Procedures').all();
for (let i = 0; i < updateItems.length; i++) {
  const u = updateItems[i].json;
  const p = pendingItems[i] ? pendingItems[i].json : {};
  const procs = Array.isArray(p.pending_procedures) ? p.pending_procedures : [];
  const paid_at = u.paid_at || new Date().toISOString();
  for (const proc of procs) {
    out.push({ json: {
      order_id: u.id,
      procedure_id: proc.id != null ? proc.id : null,
      procedure_name: proc.name || proc.procedure_name || 'Procedure',
      room_number: String(proc.room || proc.room_number || ''),
      amount: Number(proc.price) || 0,
      paid_at,
      state: 'pending'
    }});
  }
}
return out.length ? out : [{ json: {} }];

const fmtVnd = (n) => (n != null ? new Intl.NumberFormat('vi-VN', { maximumFractionDigits: 0 }).format(Number(n)) + ' ₫' : '—');
const fmtTime = (s) => { if (!s) return '—'; try { return new Date(s).toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh', dateStyle: 'medium', timeStyle: 'short' }); } catch { return String(s); } };
const out = [];
for (const item of $input.all()) { const d = item.json; if (!d.email) continue; out.push({ json: { email: d.email, orderNumber: d.order_number, userName: d.user_name || 'Customer', procedureName: d.procedure_name || '—', roomNumber: d.room_number || '—', totalAmount: fmtVnd(d.total_amount), paidAt: fmtTime(d.paid_at) } }); }
return out;
